class Solution(object):
    def findClosestElements(self, arr, k, x):
        import bisect
        idx = bisect.bisect_left(arr, x)
        left, right = max(0, idx - k), min(len(arr) - k, idx)
        while right - left > k:
            if x - arr[left] < arr[right + k - 1] - x:
                right -= 1
            else:
                left += 1
        return arr[left:left+k]
